package main

import "fmt"

type Config struct {
    Host string
    Port int
}

func main() {
    // new
    p := new(int)
    fmt.Println("new(int):", *p)

    // new with struct
    cfg := new(Config)
    cfg.Host = "localhost"
    cfg.Port = 8080
    fmt.Println("Config:", cfg.Host, cfg.Port)

    // &T{} is more idiomatic
    cfg2 := &Config{Host: "example.com", Port: 443}
    fmt.Println("Config2:", cfg2.Host, cfg2.Port)
}
